        if s.isdigit():
            idx = int(s) - 1
            if 0 <= idx < len(self.chats):
                self._set_active_chat(idx)
                return True

        for idx, chat in enumerate(self.chats):
            if chat["session_id"] == s or chat["title"] == s:
                self._set_active_chat(idx)
                return True

        return False

